mapper.delete:
DELETE FROM t_mq_outbox
WHERE status = 'SENT'
  AND created_at < #{cutoff}

mapper.select:
SELECT COUNT(*)
FROM t_mq_outbox
WHERE status = #{status}

SELECT id, event_type, exchange, routing_key, payload::text AS payload, headers::text AS headers, status, next_retry_at, last_error, claimed_at, claimed_by, retry_count, version, created_at FROM t_mq_outbox
AND headers ->> 'x-event-id' = #{eventId}
AND headers ->> 'x-idempotency-key' = #{idempotencyKey}
AND status = #{status}
ORDER BY created_at DESC LIMIT #{limit}
